// Generate a unique worker ID for this execution
const workerId = `wf2_${$execution.id.substring(0, 12)}_${Date.now()}`;
return [{ json: { worker_id: workerId } }];

const lead = $('Fetch Lead Data').item.json;
const job = $('Pick 1 Job from Queue').item.json;

const supportedLangs = ['Español', 'Francés', 'Inglés', 'Italiano'];
const lang = supportedLangs.includes(lead.language) ? lead.language : 'Inglés';
const firstName = lead.first_name || lead.full_name || 'Student';
const titling = (lead.titling || lead.tipo_producto || 'tu programa')
  .replace(/^-\s*/, '').replace(/\s*-$/, '').replace(/\.\s*$/, '').trim();

const idempotencyKey = `cold_email:${lead.id}`;

const templates = {
  'Español': {
    subject: `Siguiente paso: Homologación de tus estudios para ${titling}`,
    greeting: `Hola ${firstName},`,
    body: `<p style="margin:0 0 12px 0;font-size:16px;line-height:1.6"><strong>¡Felicidades</strong> por tu admisión al programa de <strong>${titling}</strong> en la Universidad Europea! 🎉 Sabemos lo importante que es para ti dar este paso y queremos que tu inicio sea lo más fácil posible.</p><p style="margin:0 0 12px 0;font-size:16px;line-height:1.6">Para comenzar, necesitarás realizar la <strong>homologación de tus estudios previos</strong>. Es un requisito indispensable, pero no tienes por qué preocuparte: en <em>Space for Edu</em> nos encargamos de guiarte y simplificar todo el proceso.</p><p style="margin:16px 0 8px 0;font-size:16px;line-height:1.6"><strong>Estamos aquí para que:</strong></p><ul style="margin:0 0 12px 22px;padding:0;font-size:16px;line-height:1.6"><li style="margin:0 0 6px 0">No pierdas tiempo con trámites confusos.</li><li style="margin:0 0 6px 0">Tengas la tranquilidad de que tu documentación esté en regla.</li><li style="margin:0 0 6px 0">Te enfoques en lo que realmente importa: tus estudios y tu futuro.</li></ul><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">¿Prefieres que te contactemos por <strong>WhatsApp</strong> o por <strong>teléfono</strong>? También nos puedes escribir al <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a> o a <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>.</p><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Visita nuestra web: <a href="https://spaceforedu.com/es/space-edu-espanol/" style="color:#0b69ff;text-decoration:none">spaceforedu.com</a></p><p style="margin:0 0 16px 0;font-size:16px;line-height:1.6">Con mucho gusto te acompañaremos en este paso importante.</p><p style="margin:0 0 2px 0;font-size:16px;line-height:1.6">Quedo pendiente,</p><p style="margin:0 0 18px 0;font-size:16px;line-height:1.6">Saludos,</p>`,
    disclaimer: `De conformidad con la Ley Orgánica 3/2018 y el Reglamento (UE) 2016/679, los datos personales serán tratados por ROSFORD SL. Puede ejercer sus derechos escribiendo a <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a> o a CALLE BAHIA DE ALICANTE 82 PISO 1 D (28042) MADRID. Reclamaciones: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Inglés': {
    subject: `Next Step: Homologation of Your Studies for ${titling}`,
    greeting: `Dear ${firstName},`,
    body: `<p style="margin:0 0 12px 0;font-size:16px;line-height:1.6"><strong>Congratulations</strong> on your admission to the <strong>${titling}</strong> program at Universidad Europea! 🎉 We want to make your start as easy as possible.</p><p style="margin:0 0 12px 0;font-size:16px;line-height:1.6">To begin, you will need to complete the <strong>recognition (homologation) of your previous education</strong>. At <em>Space for Edu</em> we guide you and simplify the entire process.</p><p style="margin:16px 0 8px 0;font-size:16px;line-height:1.6"><strong>We are here so that:</strong></p><ul style="margin:0 0 12px 22px;padding:0;font-size:16px;line-height:1.6"><li style="margin:0 0 6px 0">You don't waste time with confusing procedures.</li><li style="margin:0 0 6px 0">Your documentation is in order.</li><li style="margin:0 0 6px 0">You focus on what matters: your studies and your future.</li></ul><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Would you prefer <strong>WhatsApp</strong> or <strong>phone</strong>? Write to us at <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a> or <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>.</p><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Visit our website: <a href="https://spaceforedu.com/en/space-edu-english/" style="color:#0b69ff;text-decoration:none">spaceforedu.com</a></p><p style="margin:0 0 16px 0;font-size:16px;line-height:1.6">We will be happy to accompany you in this important step.</p><p style="margin:0 0 2px 0;font-size:16px;line-height:1.6">Looking forward to assisting you,</p><p style="margin:0 0 18px 0;font-size:16px;line-height:1.6">Best regards,</p>`,
    disclaimer: `In accordance with Organic Law 3/2018 and Regulation (EU) 2016/679, personal data will be processed by ROSFORD SL. Exercise your rights at <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Claims: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Francés': {
    subject: `Prochaine étape : Homologation de vos études pour ${titling}`,
    greeting: `Bonjour ${firstName},`,
    body: `<p style="margin:0 0 12px 0;font-size:16px;line-height:1.6"><strong>Félicitations</strong> pour votre admission au programme <strong>${titling}</strong> à l'Universidad Europea ! 🎉 Nous voulons faciliter au maximum vos débuts.</p><p style="margin:0 0 12px 0;font-size:16px;line-height:1.6">Vous devrez effectuer <strong>l'homologation de vos études antérieures</strong>. Chez <em>Space for Edu</em>, nous simplifions tout le processus.</p><p style="margin:16px 0 8px 0;font-size:16px;line-height:1.6"><strong>Nous sommes là pour que :</strong></p><ul style="margin:0 0 12px 22px;padding:0;font-size:16px;line-height:1.6"><li style="margin:0 0 6px 0">Vous ne perdiez pas de temps avec des démarches complexes.</li><li style="margin:0 0 6px 0">Votre documentation soit en règle.</li><li style="margin:0 0 6px 0">Vous vous concentriez sur l'essentiel : vos études.</li></ul><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Préférez-vous <strong>WhatsApp</strong> ou <strong>téléphone</strong> ? Écrivez-nous au <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a> ou à <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>.</p><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Visitez notre site : <a href="https://spaceforedu.com/" style="color:#0b69ff;text-decoration:none">spaceforedu.com</a></p><p style="margin:0 0 2px 0;font-size:16px;line-height:1.6">Dans l'attente de votre réponse,</p><p style="margin:0 0 18px 0;font-size:16px;line-height:1.6">Cordialement,</p>`,
    disclaimer: `Conformément à la Loi Organique 3/2018 et au Règlement (UE) 2016/679, les données personnelles seront traitées par ROSFORD SL. Droits : <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Réclamations : <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  },
  'Italiano': {
    subject: `Prossimo passo: Omologazione dei tuoi studi per ${titling}`,
    greeting: `Ciao ${firstName},`,
    body: `<p style="margin:0 0 12px 0;font-size:16px;line-height:1.6"><strong>Congratulazioni</strong> per la tua ammissione al programma <strong>${titling}</strong> presso l'Universidad Europea! 🎉 Vogliamo rendere il tuo inizio il più semplice possibile.</p><p style="margin:0 0 12px 0;font-size:16px;line-height:1.6">Dovrai completare <strong>l'omologazione dei tuoi studi precedenti</strong>. A <em>Space for Edu</em> ci occupiamo di guidarti e semplificare tutto.</p><p style="margin:16px 0 8px 0;font-size:16px;line-height:1.6"><strong>Siamo qui per:</strong></p><ul style="margin:0 0 12px 22px;padding:0;font-size:16px;line-height:1.6"><li style="margin:0 0 6px 0">Non perdere tempo con procedure complicate.</li><li style="margin:0 0 6px 0">La tua documentazione sia in regola.</li><li style="margin:0 0 6px 0">Concentrarti sui tuoi studi e il tuo futuro.</li></ul><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Preferisci <strong>WhatsApp</strong> o <strong>telefono</strong>? Scrivici al <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">+34 635 52 75 94</a> o a <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>.</p><p style="margin:12px 0 12px 0;font-size:16px;line-height:1.6">Visita il nostro sito: <a href="https://spaceforedu.com/" style="color:#0b69ff;text-decoration:none">spaceforedu.com</a></p><p style="margin:0 0 2px 0;font-size:16px;line-height:1.6">In attesa di un tuo riscontro,</p><p style="margin:0 0 18px 0;font-size:16px;line-height:1.6">Cordiali saluti,</p>`,
    disclaimer: `Ai sensi della Legge Organica 3/2018 e del Regolamento (UE) 2016/679, i dati personali saranno trattati da ROSFORD SL. Diritti: <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a>. Reclami: <a href="https://www.aepd.es" style="color:#0b69ff;text-decoration:none">www.aepd.es</a>.`
  }
};

const t = templates[lang];
const langCode = lang === 'Español' ? 'es' : lang === 'Francés' ? 'fr' : lang === 'Italiano' ? 'it' : 'en';

const bodyHtml = `<!doctype html><html lang="${langCode}"><head><meta charset="utf-8"><meta name="x-apple-disable-message-reformatting"><meta name="format-detection" content="telephone=no, date=no, address=no, email=no"></head><body style="margin:0;padding:0;background:#f5f7fa"><center style="width:100%;background:#f5f7fa"><table role="presentation" cellspacing="0" cellpadding="0" border="0" align="center" width="100%" style="max-width:600px;margin:0 auto;background:#ffffff"><tr><td style="padding:28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#111"><p style="margin:0 0 14px 0;font-size:16px;line-height:1.5">${t.greeting}</p>${t.body}</td></tr><tr><td style="padding:0 28px 24px 28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td style="width:200px;vertical-align:top;padding-right:20px"><img src="https://spaceforedu.com/assets/SFE_Small_logo.jpg" alt="Space for Edu" width="160" style="display:block;border:0"></td><td style="vertical-align:top"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="border:1px solid #e6e8eb;border-radius:12px"><tr><td style="padding:16px 20px"><p style="margin:0;font-size:18px;line-height:1.4;font-weight:700;color:#111">Matvey Sinelnik</p><p style="margin:2px 0 10px 0;font-size:14px;color:#555;line-height:1.4">Director — Rosford SL</p><p style="margin:0;font-size:14px;color:#111;line-height:1.7">📞 <a href="tel:+34635527594" style="color:#0b69ff;text-decoration:none">(+34) 635 52 75 94</a><br>✉️ <a href="mailto:center@spaceforedu.com" style="color:#0b69ff;text-decoration:none">center@spaceforedu.com</a><br>🌐 <a href="https://www.spaceforedu.com" style="color:#0b69ff;text-decoration:none">www.spaceforedu.com</a></p></td></tr></table></td></tr></table></td></tr><tr><td style="padding:0 28px 28px 28px;font-family:Segoe UI,Roboto,Helvetica,Arial,sans-serif"><p style="margin:0;font-size:12px;line-height:1.6;color:#6b7280">${t.disclaimer}</p></td></tr></table></center></body></html>`;

const bodyText = bodyHtml.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

return [{
  json: {
    queue_id: job.queue_id,
    lead_id: lead.id,
    email: lead.email,
    first_name: firstName,
    subject: t.subject,
    body_html: bodyHtml,
    body_text: bodyText,
    language: lang,
    idempotency_key: idempotencyKey,
    attempt_count: job.attempt_count
  }
}];
